export interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult {
  rows: Record<string, any>[];
  headers: string[];
  errors: CSVError[];
  filter(predicate: (row: Record<string, any>) => boolean): Record<string, any>[];
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<any, Record<string, any>[]>;
}

const DEFAULT_DELIMITER = ',';
const DEFAULT_QUOTE = '"';
const DEFAULT_LINE_SEPARATOR = '\n';

function normalizeLineEndings(value: string): string {
  return value.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
}

function isNumericString(value: string): boolean {
  return /^[-+]?(?:\d+(?:\.\d*)?|\.\d+)(?:[eE][-+]?\d+)?$/.test(value);
}

function coerceValue(rawValue: string): string | number | boolean | null {
  const trimmed = rawValue.trim();
  if (trimmed === '') {
    return null;
  }
  const lower = trimmed.toLowerCase();
  if (lower === 'null') {
    return null;
  }
  if (lower === 'true') {
    return true;
  }
  if (lower === 'false') {
    return false;
  }
  if (isNumericString(trimmed)) {
    return Number(trimmed);
  }
  return rawValue;
}

interface SplitResult {
  rows: string[][];
  hadUnclosedQuote: boolean;
  unclosedQuoteRow: number | null;
}

function splitToRows(
  input: string,
  delimiter: string,
  quoteChar: string,
  lineSeparator: string
): SplitResult {
  const rows: string[][] = [];
  let currentRow: string[] = [];
  let field = '';
  let inQuotes = false;
  let index = 0;
  const lineSepLen = lineSeparator.length;
  let currentRowNumber = 1;

  while (index < input.length) {
    const char = input[index];

    if (char === quoteChar) {
      if (inQuotes && input[index + 1] === quoteChar) {
        field += quoteChar;
        index += 2;
        continue;
      }
      inQuotes = !inQuotes;
      index++;
      continue;
    }

    if (!inQuotes && lineSepLen > 0 && input.startsWith(lineSeparator, index)) {
      currentRow.push(field);
      rows.push(currentRow);
      currentRow = [];
      field = '';
      index += lineSepLen;
      currentRowNumber++;
      continue;
    }

    if (!inQuotes && char === delimiter) {
      currentRow.push(field);
      field = '';
      index++;
      continue;
    }

    field += char;
    index++;
  }

  if (field.length > 0 || currentRow.length > 0) {
    currentRow.push(field);
    rows.push(currentRow);
  }

  return {
    rows,
    hadUnclosedQuote: inQuotes,
    unclosedQuoteRow: inQuotes ? currentRowNumber : null,
  };
}

export function parseCSV(input: string, options: CSVOptions = {}): CSVResult {
  const delimiter = options.delimiter && options.delimiter.length > 0 ? options.delimiter : DEFAULT_DELIMITER;
  const quoteChar = options.quote && options.quote.length > 0 ? options.quote : DEFAULT_QUOTE;
  const lineSeparator = options.lineSeparator && options.lineSeparator.length > 0 ? options.lineSeparator : DEFAULT_LINE_SEPARATOR;
  const shouldNormalizeLineEndings = !options.lineSeparator || options.lineSeparator === DEFAULT_LINE_SEPARATOR;
  const normalizedInput = shouldNormalizeLineEndings ? normalizeLineEndings(input) : input;

  if (normalizedInput.length === 0) {
    const emptyResult: CSVResult = {
      headers: [],
      rows: [],
      errors: [],
      filter: () => [],
      sum: () => 0,
      average: () => 0,
      count: () => 0,
      groupBy: () => new Map(),
    };
    return emptyResult;
  }

  const { rows: parsedRows, hadUnclosedQuote, unclosedQuoteRow } = splitToRows(
    normalizedInput,
    delimiter,
    quoteChar,
    lineSeparator
  );

  if (parsedRows.length === 0) {
    const emptyResult: CSVResult = {
      headers: [],
      rows: [],
      errors: [],
      filter: () => [],
      sum: () => 0,
      average: () => 0,
      count: () => 0,
      groupBy: () => new Map(),
    };
    return emptyResult;
  }

  const headerRow = parsedRows[0];
  const headers = headerRow.slice();
  const errors: CSVError[] = [];

  if (hadUnclosedQuote && unclosedQuoteRow !== null) {
    errors.push({
      row: unclosedQuoteRow,
      message: 'Unclosed quoted field',
    });
  }

  const processedRows: Record<string, any>[] = [];

  for (let rowIndex = 1; rowIndex < parsedRows.length; rowIndex += 1) {
    const rawRow = parsedRows[rowIndex];
    const rowNumber = rowIndex + 1;
    if (rawRow.length !== headers.length) {
      errors.push({
        row: rowNumber,
        message: `Expected ${headers.length} fields but got ${rawRow.length}`,
      });
      continue;
    }

    const record: Record<string, any> = {};
    for (let columnIndex = 0; columnIndex < headers.length; columnIndex += 1) {
      const headerName = headers[columnIndex];
      const rawValue = rawRow[columnIndex] ?? '';
      record[headerName] = coerceValue(rawValue);
    }

    processedRows.push(record);
  }

  const finalRows = processedRows;

  const result: CSVResult = {
    headers,
    rows: finalRows,
    errors,
    filter(predicate: (row: Record<string, any>) => boolean) {
      return finalRows.filter(predicate);
    },
    sum(column: string) {
      return finalRows.reduce((acc, row) => {
        const value = row[column];
        if (typeof value === 'number' && !Number.isNaN(value)) {
          return acc + value;
        }
        return acc;
      }, 0);
    },
    average(column: string) {
      let total = 0;
      let count = 0;
      for (const row of finalRows) {
        const value = row[column];
        if (typeof value === 'number' && !Number.isNaN(value)) {
          total += value;
          count += 1;
        }
      }
      return count === 0 ? 0 : total / count;
    },
    count() {
      return finalRows.length;
    },
    groupBy(column: string) {
      const groups = new Map<any, Record<string, any>[]>();
      for (const row of finalRows) {
        const key = row[column];
        const existing = groups.get(key);
        if (existing) {
          existing.push(row);
        } else {
          groups.set(key, [row]);
        }
      }
      return groups;
    },
  };

  return result;
}

import { parseCSV } from './csv-parser';

function assert(condition: unknown, message: string): void {
  if (!condition) {
    throw new Error(message);
  }
}

function assertDeepEqual(actual: unknown, expected: unknown, message: string): void {
  const actualJson = JSON.stringify(actual);
  const expectedJson = JSON.stringify(expected);
  if (actualJson !== expectedJson) {
    throw new Error(`${message}\nExpected: ${expectedJson}\nActual: ${actualJson}`);
  }
}

function runTests(): void {
  // basic parsing
  const basic = parseCSV('name,age\nAlice,30\nBob,25');
  assertDeepEqual(basic.headers, ['name', 'age'], 'Headers should match the first row');
  assertDeepEqual(basic.rows, [
    { name: 'Alice', age: 30 },
    { name: 'Bob', age: 25 },
  ], 'Rows should be parsed into objects with numbers');

  // quoted fields with commas
  const quoted = parseCSV('name,notes\n"Smith, John","Likes, commas, and more"\n"Jane","Simple"');
  assert(quoted.rows.length === 2, 'There should be two parsed rows');
  assert(
    quoted.rows[0].notes === 'Likes, commas, and more',
    'Quoted fields should preserve commas inside the value'
  );

  // escaped quotes
  const escaped = parseCSV('quote\n"She said ""Hello"" to me"');
  assert(
    escaped.rows[0].quote === 'She said "Hello" to me',
    'Escaped double quotes should be reduced to single quotes inside values'
  );

  // custom delimiters, quotes, and line separators
  const custom = parseCSV("first|last~'Jane'|'Doe'", {
    delimiter: '|',
    quote: "'",
    lineSeparator: '~',
  });
  assert(custom.rows.length === 1, 'Custom line separator should split rows correctly');
  assert(custom.rows[0].first === 'Jane' && custom.rows[0].last === 'Doe', 'Custom delimiter and quote characters should be honored');

  // type coercion for numbers, booleans, nulls, and strings
  const typeInput = 'int,float,boolTrue,boolFalse,nullValue,uppercaseNull,emptyValue,text\n42,3.14,TrUe,FALSE,null,NULL,,Hello';
  const typeCoerced = parseCSV(typeInput);
  const coercedRow = typeCoerced.rows[0];
  assert(coercedRow.int === 42, 'Integers should be coerced to number');
  assert(coercedRow.float === 3.14, 'Floats should be coerced to number');
  assert(coercedRow.boolTrue === true, 'Boolean strings should parse to true');
  assert(coercedRow.boolFalse === false, 'Boolean strings should parse to false');
  assert(coercedRow.nullValue === null, 'null lowercase should become null');
  assert(coercedRow.uppercaseNull === null, 'NULL uppercase should become null');
  assert(coercedRow.emptyValue === null, 'Empty strings should become null');
  assert(coercedRow.text === 'Hello', 'Other strings should stay as string values');

  // malformed row error collection
  const malformed = parseCSV('a,b\n1,2\n3');
  assert(malformed.rows.length === 1, 'Only well-formed rows should be returned');
  assert(malformed.errors.length === 1, 'Malformed rows should be reported');
  assert(malformed.errors[0].row === 3, 'Error row numbers should match the malformed row index');
  assert(
    malformed.errors[0].message.includes('Expected 2 fields but got 1'),
    'Error message should describe the malformed row'
  );

  // filtering
  const filterResult = parseCSV('name,score\nAlice,10\nBob,25\nCara,15');
  const filteredRows = filterResult.filter((row) => row.score >= 15);
  assert(filteredRows.length === 2, 'Filter should return rows matching the predicate');
  assert(filteredRows.some((row) => row.name === 'Bob'), 'Filtered collection should contain matching rows');

  // aggregation methods
  const aggregation = parseCSV('category,value\nA,1\nB,2\nA,3\nB,4');
  assert(aggregation.sum('value') === 10, 'Sum should total numeric column values');
  assert(aggregation.average('value') === 2.5, 'Average should compute numeric averages');
  assert(aggregation.count() === 4, 'Count should return the number of data rows');
  const groups = aggregation.groupBy('category');
  assert(groups.size === 2, 'GroupBy should create entries for each category');
  assert(groups.get('A')?.length === 2 && groups.get('B')?.length === 2, 'Grouping should collect rows by column value');

  // edge cases: empty input, single column, single row, large fields
  const empty = parseCSV('');
  assert(empty.rows.length === 0 && empty.headers.length === 0, 'Empty input should produce no rows');

  const singleColumn = parseCSV('only\nvalue');
  assert(singleColumn.headers.length === 1, 'Single column headers should be parsed');
  assert(singleColumn.rows.length === 1, 'Single column data should still produce one row');
  assert(singleColumn.rows[0].only === 'value', 'Single column value should be preserved');

  const headerOnly = parseCSV('col1,col2');
  assert(headerOnly.rows.length === 0, 'Header-only input should produce zero data rows');
  assert(headerOnly.headers.length === 2, 'Header-only input should still expose header row');

  const hugeRow = parseCSV(`note,value\n"
${'x'.repeat(10000)}"`);
  assert(hugeRow.rows[0].value.length === 10000, 'Very large fields should be preserved in the output');

  console.log('All csv parser tests passed');
}

runTests();

