  assert(aggregation.average('value') === 2.5, 'Average should compute numeric averages');
  assert(aggregation.count() === 4, 'Count should return the number of data rows');
  const groups = aggregation.groupBy('category');
  assert(groups.size === 2, 'GroupBy should create entries for each category');
  assert(groups.get('A')?.length === 2 && groups.get('B')?.length === 2, 'Grouping should collect rows by column value');

  // edge cases: empty input, single column, single row, large fields
  const empty = parseCSV('');
  assert(empty.rows.length === 0 && empty.headers.length === 0, 'Empty input should produce no rows');

  const singleColumn = parseCSV('only\nvalue');
  assert(singleColumn.headers.length === 1, 'Single column headers should be parsed');
  assert(singleColumn.rows.length === 1, 'Single column data should still produce one row');
  assert(singleColumn.rows[0].only === 'value', 'Single column value should be preserved');

  const headerOnly = parseCSV('col1,col2');
  assert(headerOnly.rows.length === 0, 'Header-only input should produce zero data rows');
  assert(headerOnly.headers.length === 2, 'Header-only input should still expose header row');

  const hugeRow = parseCSV(`note,value\n"${'x'.repeat(10000)}"`);
  assert(hugeRow.rows[0].value.length === 10000, 'Very large fields should be preserved in the output');

  console.log('All csv parser tests passed');
}

