export interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult {
  rows: Record<string, any>[];
  headers: string[];
  errors: CSVError[];
  filter(predicate: (row: Record<string, any>) => boolean): Record<string, any>[];
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<any, Record<string, any>[]>;
}

const DEFAULT_DELIMITER = ',';
const DEFAULT_QUOTE = '"';
const DEFAULT_LINE_SEPARATOR = '\n';

function normalizeLineEndings(value: string): string {
  return value.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
}

function isNumericString(value: string): boolean {
  return /^[-+]?(?:\d+(?:\.\d*)?|\.\d+)(?:[eE][-+]?\d+)?$/.test(value);
}

function coerceValue(rawValue: string): string | number | boolean | null {
  const trimmed = rawValue.trim();
  if (trimmed === '') {
    return null;
  }
  const lower = trimmed.toLowerCase();
  if (lower === 'null') {
    return null;
  }
  if (lower === 'true') {
    return true;
  }
  if (lower === 'false') {
    return false;
  }
  if (isNumericString(trimmed)) {
    return Number(trimmed);
  }
  return rawValue;
}

interface SplitResult {
  rows: string[][];
  hadUnclosedQuote: boolean;
  unclosedQuoteRow: number | null;
}

function splitToRows(
  input: string,
  delimiter: string,
  quoteChar: string,
  lineSeparator: string
): SplitResult {
  const rows: string[][] = [];
  let currentRow: string[] = [];
  let field = '';
  let inQuotes = false;
  let index = 0;
  const lineSepLen = lineSeparator.length;
  let currentRowNumber = 1;

  while (index < input.length) {
    const char = input[index];

    if (char === quoteChar) {
      if (inQuotes && input[index + 1] === quoteChar) {
        field += quoteChar;
        index += 2;
        continue;
      }
      inQuotes = !inQuotes;
      index++;
      continue;
    }

    if (!inQuotes && lineSepLen > 0 && input.startsWith(lineSeparator, index)) {
      currentRow.push(field);
      rows.push(currentRow);
      currentRow = [];
      field = '';
      index += lineSepLen;
      currentRowNumber++;
      continue;
    }

    if (!inQuotes && char === delimiter) {
      currentRow.push(field);
      field = '';
      index++;
      continue;
    }

    field += char;
    index++;
  }

  if (field.length > 0 || currentRow.length > 0) {
    currentRow.push(field);
    rows.push(currentRow);
  }

  return {
    rows,
    hadUnclosedQuote: inQuotes,
    unclosedQuoteRow: inQuotes ? currentRowNumber : null,
  };
}

export function parseCSV(input: string, options: CSVOptions = {}): CSVResult {
  const delimiter = options.delimiter && options.delimiter.length > 0 ? options.delimiter : DEFAULT_DELIMITER;
  const quoteChar = options.quote && options.quote.length > 0 ? options.quote : DEFAULT_QUOTE;
  const lineSeparator = options.lineSeparator && options.lineSeparator.length > 0 ? options.lineSeparator : DEFAULT_LINE_SEPARATOR;
  const shouldNormalizeLineEndings = !options.lineSeparator || options.lineSeparator === DEFAULT_LINE_SEPARATOR;
  const normalizedInput = shouldNormalizeLineEndings ? normalizeLineEndings(input) : input;

  if (normalizedInput.length === 0) {
    const emptyResult: CSVResult = {
      headers: [],
      rows: [],
      errors: [],
      filter: () => [],
      sum: () => 0,
      average: () => 0,
      count: () => 0,
      groupBy: () => new Map(),
    };
    return emptyResult;
  }

  const { rows: parsedRows, hadUnclosedQuote, unclosedQuoteRow } = splitToRows(
    normalizedInput,
    delimiter,
    quoteChar,
    lineSeparator
  );

  if (parsedRows.length === 0) {
    const emptyResult: CSVResult = {
      headers: [],
      rows: [],
      errors: [],
      filter: () => [],
      sum: () => 0,
      average: () => 0,
      count: () => 0,
      groupBy: () => new Map(),
    };
    return emptyResult;
  }

  const headerRow = parsedRows[0];
  const headers = headerRow.slice();
  const errors: CSVError[] = [];

  if (hadUnclosedQuote && unclosedQuoteRow !== null) {
    errors.push({
      row: unclosedQuoteRow,
      message: 'Unclosed quoted field',
    });
  }

  const processedRows: Record<string, any>[] = [];

  for (let rowIndex = 1; rowIndex < parsedRows.length; rowIndex += 1) {
    const rawRow = parsedRows[rowIndex];
    const rowNumber = rowIndex + 1;
    if (rawRow.length !== headers.length) {
      errors.push({
        row: rowNumber,
        message: `Expected ${headers.length} fields but got ${rawRow.length}`,
      });
      continue;
    }

    const record: Record<string, any> = {};
    for (let columnIndex = 0; columnIndex < headers.length; columnIndex += 1) {
      const headerName = headers[columnIndex];
      const rawValue = rawRow[columnIndex] ?? '';
      record[headerName] = coerceValue(rawValue);
    }

    processedRows.push(record);
  }

  const finalRows = processedRows;

  const result: CSVResult = {
    headers,
    rows: finalRows,
    errors,
    filter(predicate: (row: Record<string, any>) => boolean) {
      return finalRows.filter(predicate);
    },
    sum(column: string) {
      return finalRows.reduce((acc, row) => {
        const value = row[column];
        if (typeof value === 'number' && !Number.isNaN(value)) {
          return acc + value;
        }
        return acc;
      }, 0);
    },
    average(column: string) {
      let total = 0;
      let count = 0;
      for (const row of finalRows) {
        const value = row[column];
        if (typeof value === 'number' && !Number.isNaN(value)) {
          total += value;
          count += 1;
        }
      }
      return count === 0 ? 0 : total / count;
    },
    count() {
      return finalRows.length;
    },
    groupBy(column: string) {
      const groups = new Map<any, Record<string, any>[]>();
      for (const row of finalRows) {
        const key = row[column];
        const existing = groups.get(key);
        if (existing) {
          existing.push(row);
        } else {
          groups.set(key, [row]);
        }
      }
      return groups;
    },
  };

  return result;
}
